import 'dart:typed_data';

import 'package:convert/convert.dart';
import 'package:dartsv/dartsv.dart';

/// Builds the locking script for the PP5 fungible token output.
///
/// PP5 holds the fungible token state: recipient, token ID, and amount.
class PP5LockBuilder extends LockingScriptBuilder {

  String template = "0176018801a901ac5101402097dfd76851bf465e8f715593b217714858bbe9570ff3bd5e33840a34e20ff0262102ba79df5f8ae7604a9830f03c7933028186aede0675a16f025dc4f8be8eec0382201008ce7480da41702918d1ec8e6849ba32b4d65b1e40dc669c31a1e6306b266c000000<recipientPKH><tokenId><amount>";

  List<int> _recipientPKH;
  List<int> _tokenId;
  int _amount;

  /// Reconstructs a [PP5LockBuilder] by parsing an existing script.
  PP5LockBuilder.fromScript(SVScript script) :
      _recipientPKH = [],
      _tokenId = [],
      _amount = 0,
      super.fromScript(script);

  /// Creates a PP5 locking script builder.
  ///
  /// [_recipientPKH] - 20-byte pubkey hash of the token recipient.
  /// [_tokenId] - 32-byte token identifier.
  /// [_amount] - The fungible token amount (encoded as 8-byte LE sign-magnitude).
  PP5LockBuilder(this._recipientPKH, this._tokenId, this._amount) {
    if (_recipientPKH.length != 20) {
      throw ScriptException(ScriptError.SCRIPT_ERR_UNKNOWN_ERROR, "Recipient PKH must be 20 bytes");
    }
    if (_tokenId.length != 32) {
      throw ScriptException(ScriptError.SCRIPT_ERR_UNKNOWN_ERROR, "Token ID must be 32 bytes");
    }
    if (_amount < 0) {
      throw ScriptException(ScriptError.SCRIPT_ERR_UNKNOWN_ERROR, "Amount must be non-negative");
    }
  }

  @override
  SVScript getScriptPubkey() {
    // Encode amount as exactly 8 bytes (LE sign-magnitude, like sCrypt's num2bin(amount, 8))
    var amountBytes = Uint8List(8);
    var val = _amount;
    for (var i = 0; i < 7; i++) {
      amountBytes[i] = val & 0xFF;
      val >>= 8;
    }
    amountBytes[7] = val & 0x7F; // clear sign bit (positive)

    var scriptHex = template
        .replaceFirst("<recipientPKH>", ScriptBuilder().addData(Uint8List.fromList(_recipientPKH)).build().toHex())
        .replaceFirst("<tokenId>", ScriptBuilder().addData(Uint8List.fromList(_tokenId)).build().toHex())
        .replaceFirst("<amount>", ScriptBuilder().addData(amountBytes).build().toHex());

    return SVScript.fromHex(scriptHex);
  }

  /// The 20-byte pubkey hash of the token recipient.
  List<int> get recipientPKH => _recipientPKH;

  /// The 32-byte token identifier.
  List<int> get tokenId => _tokenId;

  /// The fungible token amount.
  int get amount => _amount;

  @override
  void parse(SVScript script) {
    var scriptHex = hex.encode(script.buffer);

    var prefixEnd = template.indexOf('<recipientPKH>');
    var prefix = template.substring(0, prefixEnd);

    if (!scriptHex.startsWith(prefix)) {
      throw ScriptException(ScriptError.SCRIPT_ERR_UNKNOWN_ERROR, "Script does not match PP5 template");
    }

    var paramBytes = hex.decode(scriptHex.substring(prefix.length));
    var offset = 0;

    // Read recipientPKH pushdata (expected: 0x14 = 20 bytes)
    var pkhLen = paramBytes[offset];
    offset++;
    _recipientPKH = paramBytes.sublist(offset, offset + pkhLen).toList();
    offset += pkhLen;

    // Read tokenId pushdata (expected: 0x20 = 32 bytes)
    var tokenIdLen = paramBytes[offset];
    offset++;
    _tokenId = paramBytes.sublist(offset, offset + tokenIdLen).toList();
    offset += tokenIdLen;

    // Read amount pushdata (expected: 0x08 = 8 bytes)
    var amountLen = paramBytes[offset];
    offset++;
    var amountBytesList = paramBytes.sublist(offset, offset + amountLen);
    _amount = castToBigInt(amountBytesList, false, nMaxNumSize: 8).toInt();
  }
}
